  \begin {array}{l}
  \eta _{ s } : { \eta _{ J } ;s }  \sim _{ A \to  I } { \eta _{ I } }   \\ 
  \eta _{ s } a : \equiv   \mathsf { refl } 
\end {array}

  \begin {aligned}
 s { \left ( \eta _{ J } a \right )}  &  \equiv  s { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
  \\ 
                     &  \equiv  p _{ I } { \left ( \eta _{ I } a \right )} 
  \\ 
                     &  \equiv   \eta _{ I } a
\end {aligned}

  \begin {aligned}
  \eta _{ s;r } a  \bullet   \rho { \left ( \eta _{ J } a \right )} 
  &  \equiv 
  { \left ( \mathsf { ap } _{ r } { \left ( \eta _{ s } a \right )}   \bullet   \eta _{ r } a \right )}   \bullet   \rho { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
  \\ 
  &  \equiv 
  { \left ( \mathsf { ap } _{ r } \mathsf { refl }   \bullet   \mathsf { refl } \right )}   \bullet   \rho { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
  \\ 
  &  \equiv 
  { \left ( \mathsf { refl } \bullet \mathsf { refl } \right )}   \bullet   \rho { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
  \\ 
  &  \equiv 
  \mathsf { refl } \bullet   \rho { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
  \\ 
  & =
  \rho { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
\end {aligned}

  \begin {aligned}
  \rho { \left ( r { \left ( \eta _{ I } a \right )} \right )} 
  & =  \mathsf { ap } _{ r } { \left ( \vartheta _{ \eta _{ I } a } p _{ I } \right )} 
  \\ 
  &  \equiv   \mathsf { ap } _{ r }   { \left ( \eta _{ p _{ I } } a \right )} 
  \\ 
  &  \equiv   \mathsf { ap } _{ r } \mathsf { refl } 
  \\ 
  &  \equiv   \mathsf { refl } 
\end {aligned}
